func TestAuthLoginTerminalPasswordReadFailureDoesNotFallbackToPlaintext(t *testing.T) {
	oldStdinIsTerminal := stdinIsTerminal
	oldReadTerminalPassword := readTerminalPassword
	defer func() {
		stdinIsTerminal = oldStdinIsTerminal
		readTerminalPassword = oldReadTerminalPassword
	}()
	stdinIsTerminal = func(int) bool { return true }
	readTerminalPassword = func(int) ([]byte, error) { return nil, errors.New("terminal read failed") }

	cmd := newAuthLoginCmd(&rootFlags{})
	cmd.SetArgs([]string{"--email", "user@example.com"})
	err := cmd.Execute()
	if err == nil {
		t.Fatal("Execute returned nil error, want terminal password read error")
	}
	if !strings.Contains(err.Error(), "reading password") {
		t.Fatalf("error = %v, want reading password failure", err)
	}
}

func TestDeliverWebhookHonorsCanceledContext(t *testing.T) {
	t.Parallel()

	called := make(chan struct{}, 1)
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		called <- struct{}{}
		w.WriteHeader(http.StatusNoContent)
	}))
	defer server.Close()

	ctx, cancel := context.WithCancel(context.Background())
	cancel()
	err := deliverWebhook(ctx, server.URL, []byte(`{"ok":true}`), false, time.Second)
	if err == nil {
		t.Fatal("deliverWebhook returned nil error, want canceled context error")
	}
	select {
	case <-called:
		t.Fatal("webhook server was called despite canceled context")
	default:
	}
}

func TestMealAddToListDryRunResolvesRecipesByEventID(t *testing.T) {
	t.Parallel()

	configPath := filepath.Join(t.TempDir(), "config.toml")
	st, err := store.Open(&config.Config{Path: configPath})
	if err != nil {
		t.Fatalf("Open returned error: %v", err)
	}
	defer st.Close()

	if _, err := st.DB().Exec(`INSERT INTO recipes (id, name) VALUES ('recipe-1', 'Pancakes')`); err != nil {
		t.Fatalf("insert recipe: %v", err)
	}
	if _, err := st.DB().Exec(`INSERT INTO meal_events
		(id, calendar_id, date, title, details, recipe_id, label_id, sort_index, scale_factor)
		VALUES ('event-1', 'calendar-1', '2026-05-18', 'Unrelated title', '', 'recipe-1', '', 1, 1.0)`); err != nil {
		t.Fatalf("insert meal event: %v", err)
	}
	if _, err := st.DB().Exec(`INSERT INTO ingredients
		(id, recipe_id, raw_ingredient, name, quantity, sort_index)
		VALUES
		('ingredient-1', 'recipe-1', '1 cup flour', 'Flour', '1 cup', 1),
		('ingredient-2', 'recipe-1', '2 eggs', 'Eggs', '2', 2)`); err != nil {
		t.Fatalf("insert ingredients: %v", err)
	}

	flags := &rootFlags{asJSON: true, configPath: configPath}
	cmd := newMealAddToListCmd(flags)
	var out bytes.Buffer
	cmd.SetOut(&out)
	cmd.SetArgs([]string{"--list", "Groceries", "--from", "2026-05-18", "--to", "2026-05-18", "--dry-run"})
	if err := cmd.Execute(); err != nil {
		t.Fatalf("Execute returned error: %v", err)
	}
	if got := out.String(); !strings.Contains(got, `"recipe": "Pancakes"`) {
		t.Fatalf("output = %s, want recipe resolved from meal event recipe_id", got)
	}
	// PATCH: Cover dry-run JSON would_write semantics from PR review.
	var payload struct {
		Recipes []map[string]any `json:"recipes"`
	}
	if err := json.Unmarshal(out.Bytes(), &payload); err != nil {
		t.Fatalf("unmarshal output: %v\n%s", err, out.String())
	}
	if len(payload.Recipes) != 1 {
		t.Fatalf("len(recipes) = %d, want 1: %#v", len(payload.Recipes), payload.Recipes)
	}
	if got, ok := payload.Recipes[0]["would_write"].(bool); !ok || !got {
		t.Fatalf("would_write = %#v, want true during dry run", payload.Recipes[0]["would_write"])
	}
	if got, ok := payload.Recipes[0]["would_add"].(float64); !ok || got != 2 {
		t.Fatalf("would_add = %#v, want 2 during dry run", payload.Recipes[0]["would_add"])
	}
}

